attachments.value:
{%- set stream_name = stream_name | default("agentic_artifact_diff_stream") -%}
{%- set agent_id = None -%}
{# Priority 1: Get agent_id from contexts (passed via GO_TO_APP_STATE contexts) #}
{%- if all_variables and all_variables.get("context") and all_variables.context.get("agent_id") -%}
  {%- set agent_id = all_variables.context.get("agent_id") -%}
{%- elif context and context.get("agent_id") -%}
  {%- set agent_id = context.get("agent_id") -%}
{%- endif -%}
{# Priority 2: Get agent_id from request_args (query parameters) #}
{%- if not agent_id and all_variables and all_variables.get("request_args") and all_variables.request_args.get("agent_id") -%}
  {%- set agent_id = all_variables.request_args.get("agent_id") -%}
{%- endif -%}
{# Priority 3: Fallback to id if agent_id not found #}
{%- if not agent_id and all_variables and all_variables.get("context") and all_variables.context.get("id") -%}
  {%- set temp_id = all_variables.context.get("id") -%}
  {%- if temp_id and "dashboard" not in temp_id|lower and temp_id != "user-dashboard-artifact_approval_dashboard" and temp_id != "artifact-approval-dashboard" -%}
    {%- set agent_id = temp_id -%}
  {%- endif -%}
{%- elif not agent_id and context and context.get("id") -%}
  {%- set temp_id = context.id -%}
  {%- if temp_id and "dashboard" not in temp_id|lower and temp_id != "user-dashboard-artifact_approval_dashboard" and temp_id != "artifact-approval-dashboard" -%}
    {%- set agent_id = temp_id -%}
  {%- endif -%}
{%- endif -%}

{# Query the stream for all artifacts with this agent_id #}
{%- if agent_id -%}
  {%- set cfxql_query = "agent_id == '" + agent_id + "'" -%}
  {%- set all_artifacts = engine.query_stream_data(stream=stream_name, cfxql_query=cfxql_query, sorting=[{"timestamp": "desc"}]) -%}
  {# Filter by artifact_type and has_diff - be very specific to avoid cross-contamination #}
  {%- set prompt_templates = [] -%}
  {%- set toolsets = [] -%}
  {%- set personas = [] -%}
  {%- if all_artifacts -%}
    {%- for artifact in all_artifacts -%}
      {# Only include artifacts where has_diff is True #}
      {%- set has_diff = artifact.get('has_diff', False) -%}
      {%- if has_diff == True or has_diff == 'True' or has_diff == 'true' or (has_diff is string and has_diff.lower() == 'true') -%}
        {%- set artifact_type = artifact.artifact_type | default("") | string | trim -%}
        {%- set artifact_type_lower = artifact_type | lower | trim -%}
        {# Check for toolset - must be exactly "toolset" (case-insensitive) #}
        {%- if artifact_type_lower == "toolset" -%}
          {%- set _ = toolsets.append(artifact) -%}
        {# Check for prompt template - must be exactly "prompt template" (case-insensitive) or contain both words #}
        {%- elif artifact_type_lower == "prompt template" or (artifact_type_lower.startswith("prompt") and "template" in artifact_type_lower) -%}
          {%- set _ = prompt_templates.append(artifact) -%}
        {# Check for persona - must be exactly "persona" (case-insensitive) #}
        {%- elif artifact_type_lower == "persona" -%}
          {%- set _ = personas.append(artifact) -%}
        {%- endif -%}
      {%- endif -%}
    {%- endfor -%}
  {%- endif -%}
{%- else -%}
  {%- set all_artifacts = [] -%}
  {%- set prompt_templates = [] -%}
  {%- set toolsets = [] -%}
  {%- set personas = [] -%}
{%- endif -%}

<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Artifact Approval Dashboard</title>
  <style>
    html, body {
      margin: 0;
      padding: 0;
      height: 100%;
      width: 100%;
      background: #1e1e2f;
      color: #ffffff;
      font-family: "Segoe UI", Roboto, sans-serif;
      overflow-y: auto;
    }

    #header {
      background: #2b2b3d;
      border-bottom: 1px solid #3a3a4d;
      padding: 15px 20px;
      text-align: center;
    }

    #header .title {
      font-size: 28px;
      font-weight: 600;
      color: #7dcfff;
    }

    /* Tabs */
    .tabs-container {
      background: #24243a;
      border-bottom: 1px solid #3a3a4d;
      display: flex;
      padding: 0 20px;
    }

    .tab {
      padding: 12px 24px;
      background: transparent;
      border: none;
      border-bottom: 3px solid transparent;
      color: #c8c8dc;
      font-size: 14px;
      font-weight: 500;
      cursor: pointer;
      transition: all 0.3s;
    }

    .tab:hover {
      color: #7dcfff;
      background: #2b2b3d;
    }

    .tab.active {
      color: #7dcfff;
      border-bottom-color: #7dcfff;
      background: #2b2b3d;
    }

    .tab-content {
      display: none;
      padding: 20px;
    }

    .tab-content.active {
      display: block;
    }

    /* Artifact container */
    .artifact-container {
      background: #2b2b3d;
      border: 1px solid #3a3a4d;
      border-radius: 8px;
      padding: 20px;
      margin-bottom: 20px;
    }

    .artifact-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 15px;
      padding-bottom: 15px;
      border-bottom: 1px solid #3a3a4d;
    }

    .artifact-info {
      flex: 1;
    }

    .artifact-title {
      font-size: 16px;
      font-weight: 600;
      color: #7dcfff;
      margin-bottom: 5px;
    }

    .artifact-meta {
      font-size: 13px;
      color: #a0a0b0;
    }

    .artifact-type-badge {
      display: inline-block;
      padding: 4px 12px;
      border-radius: 12px;
      font-size: 12px;
      font-weight: 600;
      margin-right: 10px;
    }

    .artifact-type-badge.prompt-template {
      background: #4a9eff;
      color: white;
    }

    .artifact-type-badge.toolset {
      background: #7dcfff;
      color: #1e1e2f;
    }

    .artifact-type-badge.persona {
      background: #bb9af7;
      color: white;
    }

    .action-buttons {
      display: flex;
      gap: 10px;
    }

    .btn {
      padding: 8px 16px;
      border: none;
      border-radius: 6px;
      font-size: 13px;
      font-weight: 600;
      cursor: pointer;
      transition: all 0.3s;
    }

    .btn:hover {
      transform: translateY(-2px);
      box-shadow: 0 4px 8px rgba(0,0,0,0.3);
    }

    .btn-approve {
      background: #4caf50;
      color: white;
    }

    .btn-approve:hover {
      background: #45a049;
    }

    .btn-reject {
      background: #f44336;
      color: white;
    }

    .btn-reject:hover {
      background: #da190b;
    }

    .btn:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      transform: none;
    }

    .diff-wrapper {
      margin-top: 15px;
      border: 1px solid #3a3a4d;
      border-radius: 4px;
      overflow: hidden;
    }

    .diff-labels {
      display: grid;
      grid-template-columns: 1fr 1fr;
      background: #24243a;
      border-bottom: 1px solid #3a3a4d;
      padding: 8px 16px;
      font-size: 13px;
      font-weight: 600;
      color: #c8c8dc;
      position: relative;
    }

    /* Add a visible divider line in the labels row */
    .diff-labels::after {
      content: '';
      position: absolute;
      left: 50%;
      top: 0;
      bottom: 0;
      width: 3px;
      background: #606060;
      transform: translateX(-50%);
    }

    .diff-label-old {
      text-align: left;
    }

    .diff-label-new {
      text-align: right;
    }

    .diff-container {
      height: 400px;
      width: 100%;
      position: relative;
    }

    /* Remove/hide Monaco diff editor separator */
    .diff-container .monaco-split-view2.horizontal > .monaco-split-view2-view:first-child {
      border-right: none !important;
    }

    .diff-container .monaco-split-view2.horizontal > .monaco-split-view2-view:last-child {
      border-left: none !important;
    }

    /* Hide Monaco separator sash */
    .diff-container .monaco-split-view2.horizontal > .monaco-split-view2-sash {
      display: none !important;
    }

    /* Remove additional Monaco editor separator styling */
    .diff-container .monaco-editor .monaco-diff-editor .diffViewport {
      border-left: none !important;
    }

    /* Hide all possible Monaco separator elements */
    .diff-container .monaco-split-view2.horizontal > .monaco-split-view2-sash.vertical {
      display: none !important;
    }

    .no-artifacts {
      text-align: center;
      padding: 60px 20px;
      color: #7dcfff;
      font-size: 18px;
    }

    .status-message {
      margin-top: 10px;
      padding: 10px;
      border-radius: 4px;
      font-size: 14px;
      text-align: center;
      display: none;
    }

    .status-message.success {
      background: #4caf50;
      color: white;
      display: block;
    }

    .status-message.error {
      background: #f44336;
      color: white;
      display: block;
    }

    .badge-count {
      background: #4a9eff;
      color: white;
      border-radius: 12px;
      padding: 2px 8px;
      font-size: 11px;
      margin-left: 8px;
    }

    /* Sidebar styles */
    .main-layout {
      display: flex;
      height: calc(100vh - 60px);
    }

    .sidebar {
      width: 280px;
      background: #24243a;
      border-right: 1px solid #3a3a4d;
      overflow-y: auto;
      padding: 15px 0;
    }

    .sidebar-section {
      margin-bottom: 20px;
    }

    .sidebar-section-title {
      padding: 10px 20px;
      font-size: 13px;
      font-weight: 600;
      text-transform: uppercase;
      color: #7dcfff;
      letter-spacing: 1px;
      border-bottom: 1px solid #3a3a4d;
      margin-bottom: 8px;
    }

    .sidebar-item {
      padding: 10px 20px;
      cursor: pointer;
      transition: all 0.2s;
      border-left: 3px solid transparent;
      color: #c8c8dc;
      font-size: 14px;
    }

    .sidebar-item:hover {
      background: #2b2b3d;
      color: #7dcfff;
    }

    .sidebar-item.active {
      background: #2b2b3d;
      border-left-color: #7dcfff;
      color: #7dcfff;
      font-weight: 600;
    }

    .sidebar-item-name {
      display: block;
      margin-bottom: 4px;
    }

    .sidebar-item-meta {
      font-size: 11px;
      color: #94a3b8;
      opacity: 0.8;
      display: flex;
      align-items: center;
      gap: 6px;
    }

    .status-icon {
      font-size: 14px;
      font-weight: bold;
      display: inline-block;
      width: 16px;
      text-align: center;
    }

    .status-icon.accepted {
      color: #4caf50;
    }

    .status-icon.rejected {
      color: #f44336;
    }

    .status-icon.pending {
      color: #ffa726;
    }

    .content-area {
      flex: 1;
      overflow-y: auto;
      background: #1e1e2f;
    }

    /* Approval status badge */
    .approval-status-badge {
      padding: 8px 16px;
      border-radius: 6px;
      font-size: 13px;
      font-weight: 600;
      margin-bottom: 15px;
      text-align: center;
    }

    .approval-status-badge.status-accepted {
      background: #4caf50;
      color: white;
    }

    .approval-status-badge.status-rejected {
      background: #f44336;
      color: white;
    }

    /* Hide artifacts by default, show only selected */
    .artifact-container {
      display: none;
    }

    .artifact-container.active {
      display: block;
    }
  </style>

  <script src="https://cdnjs.cloudflare.com/ajax/libs/require.js/2.3.6/require.min.js"></script>
</head>
<body>
  <div id="header">
    <div class="title">Artifact Approval for Agent: <span>{{ agent_id or 'N/A' }}</span></div>
    {% if not agent_id %}
    <div style="color: #f44336; margin-top: 10px; font-size: 14px;">Warning: No agent_id found. Please check the context.</div>
    {% endif %}
  </div>

  {% if prompt_templates|length > 0 or toolsets|length > 0 or personas|length > 0 %}
  <div class="tabs-container">
    {% if prompt_templates|length > 0 %}
    <button class="tab active" onclick="switchTab('prompt-templates')">
      Prompt Templates
      <span class="badge-count">{{ prompt_templates|length }}</span>
    </button>
    {% endif %}
    {% if toolsets|length > 0 %}
    <button class="tab {% if prompt_templates|length == 0 %}active{% endif %}" onclick="switchTab('toolsets')">
      Toolsets
      <span class="badge-count">{{ toolsets|length }}</span>
    </button>
    {% endif %}
    {% if personas|length > 0 %}
    <button class="tab {% if prompt_templates|length == 0 and toolsets|length == 0 %}active{% endif %}" onclick="switchTab('personas')">
      Personas
      <span class="badge-count">{{ personas|length }}</span>
    </button>
    {% endif %}
  </div>

  <div class="main-layout">
    <!-- Sidebar -->
    <div class="sidebar" id="sidebar">
      <!-- Prompt Templates Section -->
      {% if prompt_templates|length > 0 %}
      <div class="sidebar-section" id="sidebar-prompt-templates">
        <div class="sidebar-section-title">Prompt Templates ({{ prompt_templates|length }})</div>
        {% for artifact in prompt_templates %}
          {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
          {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
          {%- if not unique_key -%}
            {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
          {%- endif -%}
          {%- set user_approval = artifact.get('user_approval', '') -%}
          <div class="sidebar-item {% if loop.first %}active{% endif %}" 
               data-artifact-key="{{ unique_key }}"
               data-artifact-type="prompt-template"
               onclick="selectArtifact('{{ unique_key }}', 'prompt-templates')">
            <span class="sidebar-item-name">
              {% if artifact.get('artifact_name') %}
                {{ artifact.artifact_name }}
              {% elif artifact.get('name') %}
                {{ artifact.name }}
              {% else %}
                Artifact #{{ loop.index }}
              {% endif %}
            </span>
            <span class="sidebar-item-meta">
              {% if user_approval %}
                {% if user_approval.lower() == 'accepted' %}
                  <span class="status-icon accepted">✓</span>
                {% elif user_approval.lower() == 'rejected' %}
                  <span class="status-icon rejected">✗</span>
                {% else %}
                  <span class="status-icon pending">○</span>
                {% endif %}
                <span>{{ user_approval }}</span>
              {% else %}
                <span class="status-icon pending">○</span>
                <span>Pending Review</span>
              {% endif %}
            </span>
          </div>
        {% endfor %}
      </div>
      {% endif %}

      <!-- Toolsets Section -->
      {% if toolsets|length > 0 %}
      <div class="sidebar-section" id="sidebar-toolsets" style="display: {% if prompt_templates|length == 0 %}block{% else %}none{% endif %};">
        <div class="sidebar-section-title">Toolsets ({{ toolsets|length }})</div>
        {% for artifact in toolsets %}
          {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
          {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
          {%- if not unique_key -%}
            {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
          {%- endif -%}
          {%- set user_approval = artifact.get('user_approval', '') -%}
          <div class="sidebar-item {% if loop.first %}active{% endif %}" 
               data-artifact-key="{{ unique_key }}"
               data-artifact-type="toolset"
               onclick="selectArtifact('{{ unique_key }}', 'toolsets')">
            <span class="sidebar-item-name">
              {% if artifact.get('artifact_name') %}
                {{ artifact.artifact_name }}
              {% elif artifact.get('name') %}
                {{ artifact.name }}
              {% else %}
                Artifact #{{ loop.index }}
              {% endif %}
            </span>
            <span class="sidebar-item-meta">
              {% if user_approval %}
                {% if user_approval.lower() == 'accepted' %}
                  <span class="status-icon accepted">✓</span>
                {% elif user_approval.lower() == 'rejected' %}
                  <span class="status-icon rejected">✗</span>
                {% else %}
                  <span class="status-icon pending">○</span>
                {% endif %}
                <span>{{ user_approval }}</span>
              {% else %}
                <span class="status-icon pending">○</span>
                <span>Pending Review</span>
              {% endif %}
            </span>
          </div>
        {% endfor %}
      </div>
      {% endif %}

      <!-- Personas Section -->
      {% if personas|length > 0 %}
      <div class="sidebar-section" id="sidebar-personas" style="display: {% if prompt_templates|length == 0 and toolsets|length == 0 %}block{% else %}none{% endif %};">
        <div class="sidebar-section-title">Personas ({{ personas|length }})</div>
        {% for artifact in personas %}
          {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
          {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
          {%- if not unique_key -%}
            {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
          {%- endif -%}
          {%- set user_approval = artifact.get('user_approval', '') -%}
          <div class="sidebar-item {% if loop.first %}active{% endif %}" 
               data-artifact-key="{{ unique_key }}"
               data-artifact-type="persona"
               onclick="selectArtifact('{{ unique_key }}', 'personas')">
            <span class="sidebar-item-name">
              {% if artifact.get('artifact_name') %}
                {{ artifact.artifact_name }}
              {% elif artifact.get('name') %}
                {{ artifact.name }}
              {% else %}
                Artifact #{{ loop.index }}
              {% endif %}
            </span>
            <span class="sidebar-item-meta">
              {% if user_approval %}
                {% if user_approval.lower() == 'accepted' %}
                  <span class="status-icon accepted">✓</span>
                {% elif user_approval.lower() == 'rejected' %}
                  <span class="status-icon rejected">✗</span>
                {% else %}
                  <span class="status-icon pending">○</span>
                {% endif %}
                <span>{{ user_approval }}</span>
              {% else %}
                <span class="status-icon pending">○</span>
                <span>Pending Review</span>
              {% endif %}
            </span>
          </div>
        {% endfor %}
      </div>
      {% endif %}
    </div>

    <!-- Content Area -->
    <div class="content-area">
      <!-- Prompt Templates Tab -->
      <div id="prompt-templates" class="tab-content {% if prompt_templates|length > 0 %}active{% endif %}">
        {% if prompt_templates|length > 0 %}
          {% for artifact in prompt_templates %}
            {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
            {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
            {%- if not unique_key -%}
              {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
            {%- endif -%}
            {%- set user_approval = artifact.get('user_approval', '') -%}
            <!-- Debug: artifact_type = {{ artifact.artifact_type }}, unique_key = {{ unique_key }}, artifact_name = {{ artifact_name_val }} -->
            <div class="artifact-container {% if loop.first %}active{% endif %}" 
                 data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                 data-artifact-type="{{ artifact.artifact_type }}" 
                 data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}"
                 data-artifact-key="{{ unique_key }}">
              {% if user_approval %}
              <div class="approval-status-badge status-{{ user_approval.lower() }}">
                {% if user_approval == 'Accepted' %}✓ Accepted{% else %}✗ Rejected{% endif %}
              </div>
              {% endif %}
              <div class="artifact-header">
            <div class="artifact-info">
              <div class="artifact-title">
                <span class="artifact-type-badge prompt-template">{{ artifact.artifact_type }}</span>
                {% if artifact.get('artifact_name') %}
                  {{ artifact.artifact_name }}
                {% elif artifact.get('name') %}
                  {{ artifact.name }}
                {% else %}
                  Artifact #{{ loop.index }}
                {% endif %}
              </div>
              <div class="artifact-meta">
                {% if artifact.timestamp %}
                  Timestamp: {{ artifact.timestamp }}
                {% endif %}
              </div>
            </div>
            <div class="action-buttons">
              <button class="btn btn-approve" 
                      data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                      data-artifact-type="{{ artifact.artifact_type }}" 
                      data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}" 
                      data-unique-key="{{ unique_key }}"
                      data-approval-action="Accepted">
                Accept
              </button>
              <button class="btn btn-reject" 
                      data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                      data-artifact-type="{{ artifact.artifact_type }}" 
                      data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}" 
                      data-unique-key="{{ unique_key }}"
                      data-approval-action="Rejected">
                Reject
              </button>
            </div>
          </div>
              <div id="status-{{ unique_key }}" class="status-message"></div>
              <div class="diff-wrapper">
                <div class="diff-labels">
                  <div class="diff-label-old">Old Content</div>
                  <div class="diff-label-new">New Content</div>
                </div>
                <div class="diff-container" id="diff-{{ unique_key }}" data-artifact-key="{{ unique_key }}"></div>
              </div>
            </div>
          {% endfor %}
        {% else %}
          <div class="no-artifacts">No Prompt Template artifacts to review</div>
        {% endif %}
      </div>

      <!-- Toolsets Tab -->
      <div id="toolsets" class="tab-content {% if toolsets|length > 0 and prompt_templates|length == 0 %}active{% endif %}">
        {% if toolsets|length > 0 %}
          {% for artifact in toolsets %}
            {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
            {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
            {%- if not unique_key -%}
              {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
            {%- endif -%}
            {%- set user_approval = artifact.get('user_approval', '') -%}
            <!-- Debug: artifact_type = {{ artifact.artifact_type }}, unique_key = {{ unique_key }}, artifact_name = {{ artifact_name_val }} -->
            <div class="artifact-container {% if loop.first %}active{% endif %}" 
                 data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                 data-artifact-type="{{ artifact.artifact_type }}" 
                 data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}"
                 data-artifact-key="{{ unique_key }}">
              {% if user_approval %}
              <div class="approval-status-badge status-{{ user_approval.lower() }}">
                {% if user_approval == 'Accepted' %}✓ Accepted{% else %}✗ Rejected{% endif %}
              </div>
              {% endif %}
              <div class="artifact-header">
            <div class="artifact-info">
              <div class="artifact-title">
                <span class="artifact-type-badge toolset">{{ artifact.artifact_type }}</span>
                {% if artifact.get('artifact_name') %}
                  {{ artifact.artifact_name }}
                {% elif artifact.get('name') %}
                  {{ artifact.name }}
                {% else %}
                  Artifact #{{ loop.index }}
                {% endif %}
              </div>
              <div class="artifact-meta">
                {% if artifact.timestamp %}
                  Timestamp: {{ artifact.timestamp }}
                {% endif %}
              </div>
            </div>
            <div class="action-buttons">
              <button class="btn btn-approve" 
                      data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                      data-artifact-type="{{ artifact.artifact_type }}" 
                      data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}" 
                      data-unique-key="{{ unique_key }}"
                      data-approval-action="Accepted">
                Approve
              </button>
              <button class="btn btn-reject" 
                      data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                      data-artifact-type="{{ artifact.artifact_type }}" 
                      data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}" 
                      data-unique-key="{{ unique_key }}"
                      data-approval-action="Rejected">
                Reject
              </button>
            </div>
          </div>
              <div id="status-{{ unique_key }}" class="status-message"></div>
              <div class="diff-wrapper">
                <div class="diff-labels">
                  <div class="diff-label-old">Old Content</div>
                  <div class="diff-label-new">New Content</div>
                </div>
                <div class="diff-container" id="diff-{{ unique_key }}" data-artifact-key="{{ unique_key }}"></div>
              </div>
            </div>
          {% endfor %}
        {% else %}
          <div class="no-artifacts">No Toolset artifacts to review</div>
        {% endif %}
      </div>

      <!-- Personas Tab -->
      <div id="personas" class="tab-content {% if personas|length > 0 and prompt_templates|length == 0 and toolsets|length == 0 %}active{% endif %}">
        {% if personas|length > 0 %}
          {% for artifact in personas %}
            {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
            {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
            {%- if not unique_key -%}
              {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
            {%- endif -%}
            {%- set user_approval = artifact.get('user_approval', '') -%}
            <!-- Debug: artifact_type = {{ artifact.artifact_type }}, unique_key = {{ unique_key }}, artifact_name = {{ artifact_name_val }} -->
            <div class="artifact-container {% if loop.first %}active{% endif %}" 
                 data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                 data-artifact-type="{{ artifact.artifact_type }}" 
                 data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}"
                 data-artifact-key="{{ unique_key }}">
              {% if user_approval %}
              <div class="approval-status-badge status-{{ user_approval.lower() }}">
                {% if user_approval == 'Accepted' %}✓ Accepted{% else %}✗ Rejected{% endif %}
              </div>
              {% endif %}
              <div class="artifact-header">
            <div class="artifact-info">
              <div class="artifact-title">
                <span class="artifact-type-badge persona">{{ artifact.artifact_type }}</span>
                {% if artifact.get('artifact_name') %}
                  {{ artifact.artifact_name }}
                {% elif artifact.get('name') %}
                  {{ artifact.name }}
                {% else %}
                  Artifact #{{ loop.index }}
                {% endif %}
              </div>
              <div class="artifact-meta">
                {% if artifact.timestamp %}
                  Timestamp: {{ artifact.timestamp }}
                {% endif %}
              </div>
            </div>
            <div class="action-buttons">
              <button class="btn btn-approve" 
                      data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                      data-artifact-type="{{ artifact.artifact_type }}" 
                      data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}" 
                      data-unique-key="{{ unique_key }}"
                      data-approval-action="Accepted">
                Approve
              </button>
              <button class="btn btn-reject" 
                      data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                      data-artifact-type="{{ artifact.artifact_type }}" 
                      data-artifact-name="{{ artifact.get('artifact_name', '') or artifact.get('name', '') }}" 
                      data-unique-key="{{ unique_key }}"
                      data-approval-action="Rejected">
                Reject
              </button>
            </div>
          </div>
              <div id="status-{{ unique_key }}" class="status-message"></div>
              <div class="diff-wrapper">
                <div class="diff-labels">
                  <div class="diff-label-old">Old Content</div>
                  <div class="diff-label-new">New Content</div>
                </div>
                <div class="diff-container" id="diff-{{ unique_key }}" data-artifact-key="{{ unique_key }}"></div>
              </div>
            </div>
          {% endfor %}
        {% else %}
          <div class="no-artifacts">No Persona artifacts to review</div>
        {% endif %}
      </div>
    </div>
  </div>
  {% else %}
  <!-- No artifacts with differences -->
  <div class="no-artifacts" style="padding: 80px 20px;">
    <div style="font-size: 24px; margin-bottom: 10px;">✓ All Clear</div>
    <div>No artifacts with differences found for this agent.</div>
  </div>
  {% endif %}

  <script>
    // Artifact data from template - include unique identifier for updates
    // Use a consistent unique key that matches the HTML template
    // Only include artifacts where has_diff is True
    window.artifacts = [
      {% for artifact in all_artifacts %}
      {%- set has_diff = artifact.get('has_diff', False) -%}
      {%- if has_diff == True or has_diff == 'True' or has_diff == 'true' or (has_diff is string and has_diff.lower() == 'true') -%}
      {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
      {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
      {%- if not unique_key -%}
        {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
      {%- endif -%}
      {
        unique_key: {{ unique_key | tojson }},
        id: "{{ artifact.get('agent_id', artifact.id) }}",
        agent_id: "{{ artifact.get('agent_id', artifact.id) }}",
        artifact_type: "{{ artifact.artifact_type }}",
        artifact_name: {{ artifact_name_val | tojson }},
        old_artifact_content: {{ artifact.old_artifact_content | default("") | tojson }},
        new_artifact_content: {{ artifact.new_artifact_content | default("") | tojson }},
        old_content: {{ artifact.old_artifact_content | default("") | tojson }},
        new_content: {{ artifact.new_artifact_content | default("") | tojson }},
        timestamp: {{ artifact.timestamp | default("") | tojson }},
        _RDA_Id: {{ artifact.get('_RDA_Id', '') | tojson }}
      }{{ "," if not loop.last else "" }}
      {%- endif -%}
      {% endfor %}
    ];
    
    // Create a map for quick lookup by unique_key (convert to string for consistent lookup)
    window.artifactsMap = {};
    window.artifacts.forEach(artifact => {
      window.artifactsMap[String(artifact.unique_key)] = artifact;
    });
    
    // Debug: log artifacts map for troubleshooting
    console.log('Artifacts map:', window.artifactsMap);
    console.log('All artifacts:', window.artifacts);

    window.agentId = "{{ agent_id }}";
    window.streamName = "{{ stream_name }}";
    window.RTYPE = "upload-agent-test";

    // Tab switching
    window.switchTab = function(tabName) {
      // Hide all tab contents
      document.querySelectorAll('.tab-content').forEach(content => {
        content.classList.remove('active');
      });
      
      // Remove active class from all tabs
      document.querySelectorAll('.tab').forEach(tab => {
        tab.classList.remove('active');
      });
      
      // Show selected tab content
      document.getElementById(tabName).classList.add('active');
      
      // Add active class to clicked tab
      if (event && event.target) {
        event.target.classList.add('active');
      } else {
        // Find the tab button and activate it
        document.querySelectorAll('.tab').forEach(tab => {
          const tabText = tab.textContent;
          if ((tabName === 'prompt-templates' && tabText.includes('Prompt Templates')) ||
              (tabName === 'toolsets' && tabText.includes('Toolsets')) ||
              (tabName === 'personas' && tabText.includes('Personas'))) {
            tab.classList.add('active');
          }
        });
      }
      
      // Show/hide sidebar sections
      const sidebarPromptTemplates = document.getElementById('sidebar-prompt-templates');
      const sidebarToolsets = document.getElementById('sidebar-toolsets');
      const sidebarPersonas = document.getElementById('sidebar-personas');
      
      if (tabName === 'prompt-templates') {
        if (sidebarPromptTemplates) sidebarPromptTemplates.style.display = 'block';
        if (sidebarToolsets) sidebarToolsets.style.display = 'none';
        if (sidebarPersonas) sidebarPersonas.style.display = 'none';
        // Select first prompt template
        const firstItem = sidebarPromptTemplates ? sidebarPromptTemplates.querySelector('.sidebar-item') : null;
        if (firstItem) {
          selectArtifact(firstItem.getAttribute('data-artifact-key'), 'prompt-templates');
        }
      } else if (tabName === 'toolsets') {
        if (sidebarPromptTemplates) sidebarPromptTemplates.style.display = 'none';
        if (sidebarToolsets) sidebarToolsets.style.display = 'block';
        if (sidebarPersonas) sidebarPersonas.style.display = 'none';
        // Select first toolset
        const firstItem = sidebarToolsets ? sidebarToolsets.querySelector('.sidebar-item') : null;
        if (firstItem) {
          selectArtifact(firstItem.getAttribute('data-artifact-key'), 'toolsets');
        }
      } else if (tabName === 'personas') {
        if (sidebarPromptTemplates) sidebarPromptTemplates.style.display = 'none';
        if (sidebarToolsets) sidebarToolsets.style.display = 'none';
        if (sidebarPersonas) sidebarPersonas.style.display = 'block';
        // Select first persona
        const firstItem = sidebarPersonas ? sidebarPersonas.querySelector('.sidebar-item') : null;
        if (firstItem) {
          selectArtifact(firstItem.getAttribute('data-artifact-key'), 'personas');
        }
      }
      
      // Reinitialize Monaco editors for the active tab
      setTimeout(() => {
        initializeEditors();
      }, 100);
    }

    // Select artifact from sidebar
    window.selectArtifact = function(artifactKey, tabName) {
      // Update sidebar active state
      document.querySelectorAll('.sidebar-item').forEach(item => {
        item.classList.remove('active');
      });
      const selectedSidebarItem = document.querySelector(`.sidebar-item[data-artifact-key="${artifactKey}"]`);
      if (selectedSidebarItem) {
        selectedSidebarItem.classList.add('active');
      }
      
      // Hide all artifacts in the current tab
      const activeTab = document.getElementById(tabName);
      if (activeTab) {
        activeTab.querySelectorAll('.artifact-container').forEach(container => {
          container.classList.remove('active');
        });
        
        // Show selected artifact
        const selectedArtifact = activeTab.querySelector(`.artifact-container[data-artifact-key="${artifactKey}"]`);
        if (selectedArtifact) {
          selectedArtifact.classList.add('active');
          // Reinitialize editor for this artifact
          setTimeout(() => {
            initializeEditors();
          }, 100);
        }
      }
    }

    // Initialize Monaco Editors
    function initializeEditors() {
      window.require.config({
        paths: {
          vs: "https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs"
        }
      });

      window.require(["vs/editor/editor.main"], function () {
        // Find all diff containers and initialize them with the correct artifact data
        document.querySelectorAll('.diff-container[data-artifact-key]').forEach(container => {
          const artifactKey = container.dataset.artifactKey;
          if (!artifactKey) {
            console.warn('Container missing artifact-key:', container);
            return;
          }
          
          // Skip if already initialized
          if (container.dataset.initialized === 'true') return;
          
          // Find the artifact by unique key - try multiple lookup methods
          let artifact = window.artifactsMap[String(artifactKey)];
          if (!artifact) {
            artifact = window.artifacts.find(a => String(a.unique_key) === String(artifactKey));
          }
          // If still not found, try matching by artifact_name or name
          if (!artifact) {
            const containerElement = container.closest('.artifact-container');
            if (containerElement) {
              const artifactName = containerElement.dataset.artifactName;
              const artifactType = containerElement.dataset.artifactType;
              const artifactId = containerElement.dataset.artifactId;
              artifact = artifacts.find(a => 
                a.id === artifactId && 
                a.artifact_type === artifactType &&
                (a.artifact_name === artifactName || String(a.artifact_name) === String(artifactName))
              );
            }
          }
          
          if (!artifact) {
            console.error('Artifact not found for key:', artifactKey);
            console.log('Available keys:', Object.keys(artifactsMap));
            console.log('Container data:', container.dataset);
            container.innerText = "Artifact data not found for key: " + artifactKey;
            return;
          }

          console.log('Initializing diff for artifact:', artifact.artifact_name || artifact.unique_key, 'with content length:', 
            (artifact.old_content || '').length, '/', (artifact.new_content || '').length);

          // Check for content - try both old_content/new_content and old_artifact_content/new_artifact_content
          const oldContent = artifact.old_content || artifact.old_artifact_content || '';
          const newContent = artifact.new_content || artifact.new_artifact_content || '';
          
          if (!oldContent || !newContent) {
            container.innerText = "Missing content data for comparison";
            console.warn('Missing content for artifact:', artifact);
            return;
          }

          // Determine language mode based on artifact type
          let languageMode = 'text/plain'; // default
          const artifactTypeLower = (artifact.artifact_type || '').toLowerCase().trim();
          if (artifactTypeLower === 'prompt template' || artifactTypeLower.includes('prompt') && artifactTypeLower.includes('template')) {
            languageMode = 'text/plain'; // Text file for Prompt Templates
          } else if (artifactTypeLower === 'toolset' || artifactTypeLower.includes('toolset')) {
            languageMode = 'yaml'; // YAML file for Toolsets
          } else if (artifactTypeLower === 'persona') {
            languageMode = 'json'; // JSON file for Personas
          }

          const originalModel = monaco.editor.createModel(
            typeof oldContent === 'string' ? oldContent : JSON.stringify(oldContent, null, 2),
            languageMode
          );
          
          const modifiedModel = monaco.editor.createModel(
            typeof newContent === 'string' ? newContent : JSON.stringify(newContent, null, 2),
            languageMode
          );

          monaco.editor.createDiffEditor(container, {
            theme: "vs-dark",
            readOnly: true,
            enableSplitViewResizing: true,
            automaticLayout: true
          }).setModel({
            original: originalModel,
            modified: modifiedModel
          });
          
          container.dataset.initialized = 'true';
        });
      });
    }

    // Handle approval/rejection - make it globally accessible
    window.handleApproval = async function(artifactId, artifactType, artifactName, approvalStatus, uniqueKey) {
      console.log('=== handleApproval called ===');
      console.log('Parameters:', { artifactId, artifactType, artifactName, approvalStatus, uniqueKey });
      // Find the artifact by unique key
      const artifact = window.artifactsMap[String(uniqueKey)] || window.artifacts.find(a => String(a.unique_key) === String(uniqueKey));
      if (!artifact) {
        throw new Error('Artifact not found');
      }
      
      const statusDiv = document.getElementById(`status-${uniqueKey}`);
      // Find container by unique key for more reliable selection
      const artifactContainer = document.querySelector(`.artifact-container[data-artifact-key="${uniqueKey}"]`);
      
      statusDiv.className = 'status-message';
      statusDiv.textContent = 'Processing...';

      try {
        // Step 1: Update the stream with user_approval
        const updateResponse = await window.updateStreamApproval(artifact, approvalStatus);
        
        // Check for errors in the response
        if (!updateResponse) {
          throw new Error('No response from update API');
        }
        
        // Check for service errors
        if (updateResponse.serviceError && updateResponse.serviceError !== 'none') {
          throw new Error(updateResponse.serviceError);
        }
        
        // Check if the update was successful
        const serviceResult = updateResponse.serviceResult;
        if (serviceResult) {
          // Check for errors in dataResults
          if (serviceResult.dataResults && serviceResult.dataResults.status === "failed") {
            throw new Error(serviceResult.dataResults.reason || "Update failed");
          }
          // Check serviceResult status
          if (serviceResult.status && serviceResult.status !== "ok" && serviceResult.status !== "SUBMIT_OK") {
            throw new Error(serviceResult.statusMessage || serviceResult.reason || "Update failed");
          }
        }

        // Success - show status indicator and keep artifact visible
        statusDiv.className = 'status-message success';
        statusDiv.textContent = `Successfully ${approvalStatus.toLowerCase()} artifact`;
        
        // Add/update status badge at the top of the artifact container
        if (artifactContainer) {
          // Remove existing status badge if any
          const existingBadge = artifactContainer.querySelector('.approval-status-badge');
          if (existingBadge) {
            existingBadge.remove();
          }
          
          // Create and add status badge
          const statusBadge = document.createElement('div');
          statusBadge.className = 'approval-status-badge';
          statusBadge.classList.add(approvalStatus.toLowerCase() === 'accepted' ? 'status-accepted' : 'status-rejected');
          statusBadge.textContent = approvalStatus === 'Accepted' ? '✓ Accepted' : '✗ Rejected';
          
          // Insert at the very top of artifact container (before any other content)
          if (artifactContainer.firstChild) {
            artifactContainer.insertBefore(statusBadge, artifactContainer.firstChild);
          } else {
            artifactContainer.appendChild(statusBadge);
          }
          
          console.log('Status badge updated for artifact:', uniqueKey, approvalStatus);
          
          // Update artifact data to reflect approval status
          if (artifact) {
            artifact.user_approval = approvalStatus;
          }
          
          // Update sidebar status with icon
          const sidebarItem = document.querySelector(`.sidebar-item[data-artifact-key="${uniqueKey}"]`);
          if (sidebarItem) {
            const metaSpan = sidebarItem.querySelector('.sidebar-item-meta');
            if (metaSpan) {
              // Determine icon based on approval status
              let iconClass = 'pending';
              let iconSymbol = '○';
              if (approvalStatus.toLowerCase() === 'accepted') {
                iconClass = 'accepted';
                iconSymbol = '✓';
              } else if (approvalStatus.toLowerCase() === 'rejected') {
                iconClass = 'rejected';
                iconSymbol = '✗';
              }
              
              // Update the meta span with icon and status
              metaSpan.innerHTML = `<span class="status-icon ${iconClass}">${iconSymbol}</span><span>${approvalStatus}</span>`;
            }
          }
        }

      } catch (error) {
        console.error('Error:', error);
        statusDiv.className = 'status-message error';
        statusDiv.textContent = `Error: ${error.message}`;
      }
    }

    // Update stream with approval status using helper template (similar to AI Learnings example)
    window.updateStreamApproval = async function(artifact, approvalStatus) {
      // Send only the query parameters - helper will query the stream to get complete data
      const queryData = {
        agent_id: artifact.agent_id || artifact.id,  // Use agent_id (not id)
        artifact_type: artifact.artifact_type,
        artifact_name: artifact.artifact_name || '',
        approval_status: approvalStatus,  // Accepted or Rejected
        stream_name: window.streamName
      };
      
      // Encode as base64 (similar to AI Learnings example)
      const jsonString = JSON.stringify(queryData);
      const base64EncodedString = btoa(jsonString);
      
      // Call helper file with base64-encoded query parameter
      // Use the full custom widget artifact API path - artifact name must match exactly
      const response = await fetch(`/api/portal/rdac/services/custom_widgets/artifact_approval_dashboard/artifact_diff_viewer/update_artifact_approval.html?query=${base64EncodedString}`, {
        method: 'GET',
        credentials: 'include'
      });
      
      const responseText = await response.text();
      
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${responseText}`);
      }
      
      try {
        const jsonResponse = JSON.parse(responseText);
        // Return in the format expected by handleApproval
        return {
          serviceError: jsonResponse.status === 'ok' ? 'none' : 'error',
          serviceResult: {
            status: jsonResponse.status === 'ok' ? 'SUBMIT_OK' : 'failed',
            statusMessage: jsonResponse.message || 'Update completed',
            dataResults: jsonResponse.result
          }
        };
      } catch (e) {
        throw new Error(`Invalid JSON response: ${responseText}`);
      }
    }


    // Attach event listeners to approve/reject buttons
    function attachButtonListeners() {
      // Find all approve and reject buttons
      const approveButtons = document.querySelectorAll('.btn-approve, .btn-reject');
      console.log('Found buttons:', approveButtons.length);
      
      approveButtons.forEach(button => {
        // Remove any existing listeners by cloning
        const newButton = button.cloneNode(true);
        button.parentNode.replaceChild(newButton, button);
        
        // Add click event listener
        newButton.addEventListener('click', function(e) {
          e.preventDefault();
          e.stopPropagation();
          
          const artifactId = this.getAttribute('data-artifact-id');
          const artifactType = this.getAttribute('data-artifact-type');
          const artifactName = this.getAttribute('data-artifact-name') || '';
          const uniqueKey = this.getAttribute('data-unique-key');
          const approvalStatus = this.getAttribute('data-approval-action');
          
          console.log('Button clicked:', { artifactId, artifactType, artifactName, uniqueKey, approvalStatus });
          
          if (window.handleApproval) {
            window.handleApproval(artifactId, artifactType, artifactName, approvalStatus, uniqueKey);
          } else {
            console.error('handleApproval function not found!');
            alert('Error: handleApproval function not found. Please refresh the page.');
          }
        });
      });
      
      console.log('Attached listeners to', approveButtons.length, 'buttons');
    }

    // Initialize editors and button listeners on page load
    window.addEventListener('DOMContentLoaded', function() {
      console.log('DOM loaded, initializing...');
      
      // Initialize sidebar - show first artifact by default
      const firstPromptTemplate = document.querySelector('#sidebar-prompt-templates .sidebar-item');
      const firstToolset = document.querySelector('#sidebar-toolsets .sidebar-item');
      const firstPersona = document.querySelector('#sidebar-personas .sidebar-item');
      
      if (firstPromptTemplate) {
        // Prompt templates exist - select the first one
        const firstKey = firstPromptTemplate.getAttribute('data-artifact-key');
        selectArtifact(firstKey, 'prompt-templates');
      } else if (firstToolset) {
        // Only toolsets exist - select the first toolset
        const firstKey = firstToolset.getAttribute('data-artifact-key');
        selectArtifact(firstKey, 'toolsets');
      } else if (firstPersona) {
        // Only personas exist - select the first persona
        const firstKey = firstPersona.getAttribute('data-artifact-key');
        selectArtifact(firstKey, 'personas');
      }
      
      initializeEditors();
      // Wait a bit for all elements to be rendered
      setTimeout(() => {
        attachButtonListeners();
      }, 100);
    });
    
    // Also try to attach listeners after a short delay in case DOMContentLoaded already fired
    setTimeout(() => {
      attachButtonListeners();
    }, 500);
  </script>
</body>
</html>

{%- set query_param = query -%}
{%- if query_param -%}
  {# Handle query parameter - decode if needed (like AI Learnings example) #}
  {%- set request_data = query_param -%}
  {%- if not (query_param is mapping) -%}
    {# Need to decode from base64 and parse JSON #}
    {%- set decoded_str = query_param | b64decode -%}
    {%- set request_data = decoded_str | from_json -%}
  {%- endif -%}
  
  {%- if request_data -%}
    {# Get parameters from request #}
    {%- set stream_name = request_data.get('stream_name', 'agentic_artifact_diff_stream') -%}
    {%- set agent_id = request_data.get('agent_id', '') -%}
    {%- set artifact_type = request_data.get('artifact_type', '') -%}
    {%- set artifact_name = request_data.get('artifact_name', '') -%}
    {%- set approval_status = request_data.get('approval_status', '') -%}
    
    {# Build CFXQL query to find the existing artifact #}
    {%- set cfxql_query = "agent_id == \"" + agent_id + "\" and artifact_type == \"" + artifact_type + "\"" -%}
    {%- if artifact_name -%}
      {%- set cfxql_query = cfxql_query + " and (artifact_name == \"" + artifact_name + "\" or name == \"" + artifact_name + "\")" -%}
    {%- endif -%}
    
    {# Query the stream to get the existing artifact data #}
    {%- set existing_artifacts = engine.query_stream_data(stream=stream_name, cfxql_query=cfxql_query) -%}
    
    {%- if existing_artifacts and existing_artifacts|length > 0 -%}
      {# Get the first matching artifact (should be unique based on agent_id, artifact_type, artifact_name) #}
      {# engine.query_stream_data returns a list - get the first artifact which contains all fields #}
      {%- set artifact_dict = {} -%}
      {%- set found = False -%}
      {%- for artifact in existing_artifacts -%}
        {%- if not found -%}
          {# Copy ALL fields generically from the existing artifact - no hardcoding #}
          {# The artifact is a dictionary/mapping, so copy all its key-value pairs #}
          {%- if artifact is mapping -%}
            {# Copy all fields from the artifact dictionary generically #}
            {%- for key, value in artifact.items() -%}
              {# Skip 'id' field - we only want agent_id in the stream #}
              {%- if key != 'id' -%}
                {%- set _ = artifact_dict.update({key: value}) -%}
              {%- endif -%}
            {%- endfor -%}
          {%- else -%}
            {# If artifact is not a mapping (e.g., pandas Series), try to convert it #}
            {# Try accessing as dictionary first #}
            {%- if hasattr(artifact, 'to_dict') -%}
              {%- set temp_dict = artifact.to_dict() -%}
              {%- for key, value in temp_dict.items() -%}
                {%- if key != 'id' -%}
                  {%- set _ = artifact_dict.update({key: value}) -%}
                {%- endif -%}
              {%- endfor -%}
            {%- elif hasattr(artifact, 'keys') -%}
              {# Try to get all keys generically and copy values #}
              {%- for key in artifact.keys() -%}
                {%- if key != 'id' -%}
                  {%- set value = artifact.get(key, '') if hasattr(artifact, 'get') else getattr(artifact, key, '') -%}
                  {%- set _ = artifact_dict.update({key: value}) -%}
                {%- endif -%}
              {%- endfor -%}
            {%- endif -%}
          {%- endif -%}
          {%- set found = True -%}
        {%- endif -%}
      {%- endfor -%}
      
      {# Add/update the user_approval field with Accepted or Rejected #}
      {%- set _ = artifact_dict.update({'user_approval': approval_status}) -%}
      
      {# Ensure only agent_id is used (remove id if it exists) #}
      {%- if 'id' in artifact_dict -%}
        {%- set _ = artifact_dict.pop('id') -%}
      {%- endif -%}
      
      {# Publish the complete updated artifact data to stream using api_client.publish_to_stream #}
      {# This publishes ALL fields from the original artifact plus the new user_approval field #}
      {%- set _ = api_client.publish_to_stream(stream_name, message=artifact_dict) -%}
      
      {"status": "ok", "message": "Approval updated successfully"}
    {%- else -%}
      {"status": "error", "message": "Artifact not found in stream"}
    {%- endif -%}
  {%- else -%}
    {"status": "error", "message": "Could not parse query data"}
  {%- endif -%}
{%- else -%}
  {"status": "error", "message": "No query data provided"}
{%- endif -%}

{%- set stream_name = stream_name | default("agentic_artifact_diff_stream") -%}
{%- set agent_id = None -%}
{# Priority 1: Get agent_id from contexts (passed via GO_TO_APP_STATE contexts) #}
{%- if all_variables and all_variables.get("context") and all_variables.context.get("agent_id") -%}
  {%- set agent_id = all_variables.context.get("agent_id") -%}
{%- elif context and context.get("agent_id") -%}
  {%- set agent_id = context.get("agent_id") -%}
{%- endif -%}
{# Priority 2: Get agent_id from request_args (query parameters) #}
{%- if not agent_id and all_variables and all_variables.get("request_args") and all_variables.request_args.get("agent_id") -%}
  {%- set agent_id = all_variables.request_args.get("agent_id") -%}
{%- endif -%}
{# Priority 3: Fallback to id if agent_id not found #}
{%- if not agent_id and all_variables and all_variables.get("context") and all_variables.context.get("id") -%}
  {%- set temp_id = all_variables.context.get("id") -%}
  {%- if temp_id and "dashboard" not in temp_id|lower and temp_id != "user-dashboard-artifact_approval_dashboard" and temp_id != "artifact-approval-dashboard" -%}
    {%- set agent_id = temp_id -%}
  {%- endif -%}
{%- elif not agent_id and context and context.get("id") -%}
  {%- set temp_id = context.id -%}
  {%- if temp_id and "dashboard" not in temp_id|lower and temp_id != "user-dashboard-artifact_approval_dashboard" and temp_id != "artifact-approval-dashboard" -%}
    {%- set agent_id = temp_id -%}
  {%- endif -%}
{%- endif -%}

{# Query the stream for all artifacts with this agent_id #}
{%- if agent_id -%}
  {%- set cfxql_query = "agent_id == '" + agent_id + "'" -%}
  {%- set all_artifacts = engine.query_stream_data(stream=stream_name, cfxql_query=cfxql_query, sorting=[{"timestamp": "desc"}]) -%}
  {# Filter by artifact_type and has_diff - be very specific to avoid cross-contamination #}
  {%- set prompt_templates = [] -%}
  {%- set toolsets = [] -%}
  {%- set personas = [] -%}
  {%- if all_artifacts -%}
    {%- for artifact in all_artifacts -%}
      {# Only include artifacts where has_diff is True #}
      {%- set has_diff = artifact.get('has_diff', False) -%}
      {%- if has_diff == True or has_diff == 'True' or has_diff == 'true' or (has_diff is string and has_diff.lower() == 'true') -%}
        {%- set artifact_type = artifact.artifact_type | default("") | string | trim -%}
        {%- set artifact_type_lower = artifact_type | lower | trim -%}
        {# Check for toolset - must be exactly "toolset" (case-insensitive) #}
        {%- if artifact_type_lower == "toolset" -%}
          {%- set _ = toolsets.append(artifact) -%}
        {# Check for prompt template - must be exactly "prompt template" (case-insensitive) or contain both words #}
        {%- elif artifact_type_lower == "prompt template" or (artifact_type_lower.startswith("prompt") and "template" in artifact_type_lower) -%}
          {%- set _ = prompt_templates.append(artifact) -%}
        {# Check for persona - must be exactly "persona" (case-insensitive) #}
        {%- elif artifact_type_lower == "persona" -%}
          {%- set _ = personas.append(artifact) -%}
        {%- endif -%}
      {%- endif -%}
    {%- endfor -%}
  {%- endif -%}
{%- else -%}
  {%- set all_artifacts = [] -%}
  {%- set prompt_templates = [] -%}
  {%- set toolsets = [] -%}
  {%- set personas = [] -%}
{%- endif -%}

