                      data-unique-key="{{ unique_key }}"
                      data-approval-action="Accepted">
                Accept
              </button>
              <button class="btn btn-reject" 
                      data-artifact-id="{{ artifact.get('agent_id', artifact.id) }}" 
                      data-artifact-type="{{ artifact.artifact_type }}" 
