  {% else %}
  <!-- No artifacts with differences -->
  <div class="no-artifacts" style="padding: 80px 20px;">
    <div style="font-size: 16px; margin-bottom: 10px;">✓ All Clear</div>
    <div style="font-size: 12px;">No artifacts with differences found for this agent.</div>
  </div>
  {% endif %}

  <script>
    // Artifact data from template - include unique identifier for updates
    // Use a consistent unique key that matches the HTML template
    // Only include artifacts where has_diff is True
    window.artifacts = [
      {% for artifact in all_artifacts %}
      {%- set has_diff = artifact.get('has_diff', False) -%}
      {%- if has_diff == True or has_diff == 'True' or has_diff == 'true' or (has_diff is string and has_diff.lower() == 'true') -%}
      {%- set artifact_name_val = artifact.get('artifact_name', '') or artifact.get('name', '') -%}
      {%- set unique_key = artifact.get('_RDA_Id', '') or artifact_name_val -%}
      {%- if not unique_key -%}
        {%- set unique_key = artifact.id ~ '-' ~ artifact.artifact_type ~ '-' ~ loop.index0 -%}
      {%- endif -%}
      {
        unique_key: {{ unique_key | tojson }},
        id: "{{ artifact.get('agent_id', artifact.id) }}",
        agent_id: "{{ artifact.get('agent_id', artifact.id) }}",
        artifact_type: "{{ artifact.artifact_type }}",
        artifact_name: {{ artifact_name_val | tojson }},
        old_artifact_content: {{ artifact.old_artifact_content | default("") | tojson }},
        new_artifact_content: {{ artifact.new_artifact_content | default("") | tojson }},
        old_content: {{ artifact.old_artifact_content | default("") | tojson }},
        new_content: {{ artifact.new_artifact_content | default("") | tojson }},
        timestamp: {{ artifact.timestamp | default("") | tojson }},
        _RDA_Id: {{ artifact.get('_RDA_Id', '') | tojson }}
      }{{ "," if not loop.last else "" }}
      {%- endif -%}
      {% endfor %}
    ];
    
    // Create a map for quick lookup by unique_key (convert to string for consistent lookup)
    window.artifactsMap = {};
    window.artifacts.forEach(artifact => {
      window.artifactsMap[String(artifact.unique_key)] = artifact;
    });
    
    // Debug: log artifacts map for troubleshooting
    console.log('Artifacts map:', window.artifactsMap);
    console.log('All artifacts:', window.artifacts);

    window.agentId = "{{ agent_id }}";
    window.streamName = "{{ stream_name }}";
    window.RTYPE = "upload-agent-test";

    // Tab switching
    window.switchTab = function(tabName) {
      // Hide all tab contents
      document.querySelectorAll('.tab-content').forEach(content => {
        content.classList.remove('active');
      });
      
      // Remove active class from all tabs
      document.querySelectorAll('.tab').forEach(tab => {
        tab.classList.remove('active');
      });
      
      // Show selected tab content
      document.getElementById(tabName).classList.add('active');
      
      // Add active class to clicked tab
      if (event && event.target) {
        event.target.classList.add('active');
      } else {
        // Find the tab button and activate it
        document.querySelectorAll('.tab').forEach(tab => {
          const tabText = tab.textContent;
          if ((tabName === 'prompt-templates' && tabText.includes('Prompt Templates')) ||
              (tabName === 'toolsets' && tabText.includes('Toolsets')) ||
              (tabName === 'personas' && tabText.includes('Personas'))) {
            tab.classList.add('active');
          }
        });
      }
      
      // Show/hide sidebar sections
      const sidebarPromptTemplates = document.getElementById('sidebar-prompt-templates');
      const sidebarToolsets = document.getElementById('sidebar-toolsets');
      const sidebarPersonas = document.getElementById('sidebar-personas');
      
      if (tabName === 'prompt-templates') {
        if (sidebarPromptTemplates) sidebarPromptTemplates.style.display = 'block';
        if (sidebarToolsets) sidebarToolsets.style.display = 'none';
        if (sidebarPersonas) sidebarPersonas.style.display = 'none';
        // Select first prompt template
        const firstItem = sidebarPromptTemplates ? sidebarPromptTemplates.querySelector('.sidebar-item') : null;
        if (firstItem) {
          selectArtifact(firstItem.getAttribute('data-artifact-key'), 'prompt-templates');
        }
      } else if (tabName === 'toolsets') {
        if (sidebarPromptTemplates) sidebarPromptTemplates.style.display = 'none';
        if (sidebarToolsets) sidebarToolsets.style.display = 'block';
        if (sidebarPersonas) sidebarPersonas.style.display = 'none';
        // Select first toolset
        const firstItem = sidebarToolsets ? sidebarToolsets.querySelector('.sidebar-item') : null;
        if (firstItem) {
          selectArtifact(firstItem.getAttribute('data-artifact-key'), 'toolsets');
        }
      } else if (tabName === 'personas') {
        if (sidebarPromptTemplates) sidebarPromptTemplates.style.display = 'none';
        if (sidebarToolsets) sidebarToolsets.style.display = 'none';
        if (sidebarPersonas) sidebarPersonas.style.display = 'block';
        // Select first persona
        const firstItem = sidebarPersonas ? sidebarPersonas.querySelector('.sidebar-item') : null;
        if (firstItem) {
          selectArtifact(firstItem.getAttribute('data-artifact-key'), 'personas');
        }
      }
      
      // Reinitialize Monaco editors for the active tab
      setTimeout(() => {
        initializeEditors();
      }, 100);
    }

    // Select artifact from sidebar
    window.selectArtifact = function(artifactKey, tabName) {
      // Update sidebar active state
      document.querySelectorAll('.sidebar-item').forEach(item => {
        item.classList.remove('active');
      });
      const selectedSidebarItem = document.querySelector(`.sidebar-item[data-artifact-key="${artifactKey}"]`);
      if (selectedSidebarItem) {
        selectedSidebarItem.classList.add('active');
      }
      
      // Hide all artifacts in the current tab
      const activeTab = document.getElementById(tabName);
      if (activeTab) {
        activeTab.querySelectorAll('.artifact-container').forEach(container => {
          container.classList.remove('active');
        });
        
        // Show selected artifact
        const selectedArtifact = activeTab.querySelector(`.artifact-container[data-artifact-key="${artifactKey}"]`);
        if (selectedArtifact) {
          selectedArtifact.classList.add('active');
          // Reinitialize editor for this artifact
          setTimeout(() => {
            initializeEditors();
          }, 100);
        }
      }
    }

    // Initialize Monaco Editors
    function initializeEditors() {
      window.require.config({
        paths: {
          vs: "https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs"
        }
      });

      window.require(["vs/editor/editor.main"], function () {
        // Find all diff containers and initialize them with the correct artifact data
        document.querySelectorAll('.diff-container[data-artifact-key]').forEach(container => {
          const artifactKey = container.dataset.artifactKey;
          if (!artifactKey) {
            console.warn('Container missing artifact-key:', container);
            return;
          }
          
          // Skip if already initialized
          if (container.dataset.initialized === 'true') return;
          
          // Find the artifact by unique key - try multiple lookup methods
          let artifact = window.artifactsMap[String(artifactKey)];
          if (!artifact) {
            artifact = window.artifacts.find(a => String(a.unique_key) === String(artifactKey));
          }
          // If still not found, try matching by artifact_name or name
          if (!artifact) {
            const containerElement = container.closest('.artifact-container');
            if (containerElement) {
              const artifactName = containerElement.dataset.artifactName;
              const artifactType = containerElement.dataset.artifactType;
              const artifactId = containerElement.dataset.artifactId;
              artifact = artifacts.find(a => 
                a.id === artifactId && 
                a.artifact_type === artifactType &&
                (a.artifact_name === artifactName || String(a.artifact_name) === String(artifactName))
              );
            }
          }
          
          if (!artifact) {
            console.error('Artifact not found for key:', artifactKey);
            console.log('Available keys:', Object.keys(artifactsMap));
            console.log('Container data:', container.dataset);
            container.innerText = "Artifact data not found for key: " + artifactKey;
            return;
          }

          console.log('Initializing diff for artifact:', artifact.artifact_name || artifact.unique_key, 'with content length:', 
            (artifact.old_content || '').length, '/', (artifact.new_content || '').length);

          // Check for content - try both old_content/new_content and old_artifact_content/new_artifact_content
          const oldContent = artifact.old_content || artifact.old_artifact_content || '';
          const newContent = artifact.new_content || artifact.new_artifact_content || '';
          
          if (!oldContent || !newContent) {
            container.innerText = "Missing content data for comparison";
            console.warn('Missing content for artifact:', artifact);
            return;
          }

          // Determine language mode based on artifact type
          let languageMode = 'text/plain'; // default
          const artifactTypeLower = (artifact.artifact_type || '').toLowerCase().trim();
          if (artifactTypeLower === 'prompt template' || artifactTypeLower.includes('prompt') && artifactTypeLower.includes('template')) {
            languageMode = 'text/plain'; // Text file for Prompt Templates
          } else if (artifactTypeLower === 'toolset' || artifactTypeLower.includes('toolset')) {
            languageMode = 'yaml'; // YAML file for Toolsets
          } else if (artifactTypeLower === 'persona') {
            languageMode = 'json'; // JSON file for Personas
          }

          const originalModel = monaco.editor.createModel(
            typeof oldContent === 'string' ? oldContent : JSON.stringify(oldContent, null, 2),
            languageMode
          );
          
          const modifiedModel = monaco.editor.createModel(
            typeof newContent === 'string' ? newContent : JSON.stringify(newContent, null, 2),
            languageMode
          );

          monaco.editor.createDiffEditor(container, {
            theme: "vs-dark",
            readOnly: true,
            enableSplitViewResizing: true,
            automaticLayout: true
          }).setModel({
            original: originalModel,
            modified: modifiedModel
          });
          
          container.dataset.initialized = 'true';
        });
      });
    }

    // Handle approval/rejection - make it globally accessible
    window.handleApproval = async function(artifactId, artifactType, artifactName, approvalStatus, uniqueKey) {
      console.log('=== handleApproval called ===');
      console.log('Parameters:', { artifactId, artifactType, artifactName, approvalStatus, uniqueKey });
      // Find the artifact by unique key
      const artifact = window.artifactsMap[String(uniqueKey)] || window.artifacts.find(a => String(a.unique_key) === String(uniqueKey));
      if (!artifact) {
        throw new Error('Artifact not found');
      }
      
      const statusDiv = document.getElementById(`status-${uniqueKey}`);
      // Find container by unique key for more reliable selection
      const artifactContainer = document.querySelector(`.artifact-container[data-artifact-key="${uniqueKey}"]`);
      
      statusDiv.className = 'status-message';
      statusDiv.textContent = 'Processing...';

      try {
        // Step 1: Update the stream with user_approval
        const updateResponse = await window.updateStreamApproval(artifact, approvalStatus);
        
        // Check for errors in the response
        if (!updateResponse) {
          throw new Error('No response from update API');
        }
        
        // Check for service errors
        if (updateResponse.serviceError && updateResponse.serviceError !== 'none') {
          throw new Error(updateResponse.serviceError);
        }
        
        // Check if the update was successful
        const serviceResult = updateResponse.serviceResult;
        if (serviceResult) {
          // Check for errors in dataResults
          if (serviceResult.dataResults && serviceResult.dataResults.status === "failed") {
            throw new Error(serviceResult.dataResults.reason || "Update failed");
          }
          // Check serviceResult status
          if (serviceResult.status && serviceResult.status !== "ok" && serviceResult.status !== "SUBMIT_OK") {
            throw new Error(serviceResult.statusMessage || serviceResult.reason || "Update failed");
          }
        }

        // Success - show status indicator and keep artifact visible
        statusDiv.className = 'status-message success';
        statusDiv.textContent = `Successfully ${approvalStatus.toLowerCase()} artifact`;
        
        // Add/update status badge at the top of the artifact container
        if (artifactContainer) {
          // Remove existing status badge if any
          const existingBadge = artifactContainer.querySelector('.approval-status-badge');
          if (existingBadge) {
            existingBadge.remove();
          }
          
          // Create and add status badge
          const statusBadge = document.createElement('div');
          statusBadge.className = 'approval-status-badge';
          statusBadge.classList.add(approvalStatus.toLowerCase() === 'accepted' ? 'status-accepted' : 'status-rejected');
          statusBadge.textContent = approvalStatus === 'Accepted' ? '✓ Accepted' : '✗ Rejected';
          
          // Insert at the very top of artifact container (before any other content)
          if (artifactContainer.firstChild) {
            artifactContainer.insertBefore(statusBadge, artifactContainer.firstChild);
          } else {
            artifactContainer.appendChild(statusBadge);
          }
          
          console.log('Status badge updated for artifact:', uniqueKey, approvalStatus);
          
          // Update artifact data to reflect approval status
          if (artifact) {
            artifact.user_approval = approvalStatus;
          }
          
          // Update sidebar status with icon
          const sidebarItem = document.querySelector(`.sidebar-item[data-artifact-key="${uniqueKey}"]`);
          if (sidebarItem) {
            const metaSpan = sidebarItem.querySelector('.sidebar-item-meta');
            if (metaSpan) {
              // Determine icon based on approval status
              let iconClass = 'pending';
              let iconSymbol = '○';
              if (approvalStatus.toLowerCase() === 'accepted') {
                iconClass = 'accepted';
                iconSymbol = '✓';
              } else if (approvalStatus.toLowerCase() === 'rejected') {
                iconClass = 'rejected';
                iconSymbol = '✗';
              }
              
              // Update the meta span with icon and status
              metaSpan.innerHTML = `<span class="status-icon ${iconClass}">${iconSymbol}</span><span>${approvalStatus}</span>`;
            }
          }
        }

      } catch (error) {
        console.error('Error:', error);
        statusDiv.className = 'status-message error';
        statusDiv.textContent = `Error: ${error.message}`;
      }
    }

    // Update stream with approval status using helper template (similar to AI Learnings example)
    window.updateStreamApproval = async function(artifact, approvalStatus) {
      // Send only the query parameters - helper will query the stream to get complete data
      const queryData = {
        agent_id: artifact.agent_id || artifact.id,  // Use agent_id (not id)
        artifact_type: artifact.artifact_type,
        artifact_name: artifact.artifact_name || '',
        approval_status: approvalStatus,  // Accepted or Rejected
        stream_name: window.streamName
      };
      
      // Encode as base64 (similar to AI Learnings example)
      const jsonString = JSON.stringify(queryData);
      const base64EncodedString = btoa(jsonString);
      
      // Call helper file with base64-encoded query parameter
      // Use the full custom widget artifact API path - artifact name must match exactly
      const response = await fetch(`/api/portal/rdac/services/custom_widgets/artifact_approval_dashboard/artifact_diff_viewer/update_artifact_approval.html?query=${base64EncodedString}`, {
        method: 'GET',
        credentials: 'include'
      });
      
      const responseText = await response.text();
      
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${responseText}`);
      }
      
      try {
        const jsonResponse = JSON.parse(responseText);
        // Return in the format expected by handleApproval
        return {
          serviceError: jsonResponse.status === 'ok' ? 'none' : 'error',
          serviceResult: {
            status: jsonResponse.status === 'ok' ? 'SUBMIT_OK' : 'failed',
            statusMessage: jsonResponse.message || 'Update completed',
            dataResults: jsonResponse.result
          }
        };
      } catch (e) {
        throw new Error(`Invalid JSON response: ${responseText}`);
      }
    }


    // Attach event listeners to approve/reject buttons
    function attachButtonListeners() {
      // Find all approve and reject buttons
      const approveButtons = document.querySelectorAll('.btn-approve, .btn-reject');
      console.log('Found buttons:', approveButtons.length);
      
      approveButtons.forEach(button => {
        // Remove any existing listeners by cloning
        const newButton = button.cloneNode(true);
        button.parentNode.replaceChild(newButton, button);
        
        // Add click event listener
        newButton.addEventListener('click', function(e) {
          e.preventDefault();
          e.stopPropagation();
          
          const artifactId = this.getAttribute('data-artifact-id');
          const artifactType = this.getAttribute('data-artifact-type');
          const artifactName = this.getAttribute('data-artifact-name') || '';
          const uniqueKey = this.getAttribute('data-unique-key');
          const approvalStatus = this.getAttribute('data-approval-action');
          
          console.log('Button clicked:', { artifactId, artifactType, artifactName, uniqueKey, approvalStatus });
          
          if (window.handleApproval) {
            window.handleApproval(artifactId, artifactType, artifactName, approvalStatus, uniqueKey);
          } else {
            console.error('handleApproval function not found!');
            alert('Error: handleApproval function not found. Please refresh the page.');
          }
        });
      });
      
      console.log('Attached listeners to', approveButtons.length, 'buttons');
    }

    // Initialize editors and button listeners on page load
    window.addEventListener('DOMContentLoaded', function() {
      console.log('DOM loaded, initializing...');
      
      // Initialize sidebar - show first artifact by default
      const firstPromptTemplate = document.querySelector('#sidebar-prompt-templates .sidebar-item');
      const firstToolset = document.querySelector('#sidebar-toolsets .sidebar-item');
      const firstPersona = document.querySelector('#sidebar-personas .sidebar-item');
      
      if (firstPromptTemplate) {
        // Prompt templates exist - select the first one
        const firstKey = firstPromptTemplate.getAttribute('data-artifact-key');
        selectArtifact(firstKey, 'prompt-templates');
      } else if (firstToolset) {
        // Only toolsets exist - select the first toolset
        const firstKey = firstToolset.getAttribute('data-artifact-key');
        selectArtifact(firstKey, 'toolsets');
      } else if (firstPersona) {
        // Only personas exist - select the first persona
        const firstKey = firstPersona.getAttribute('data-artifact-key');
        selectArtifact(firstKey, 'personas');
      }
      
      initializeEditors();
      // Wait a bit for all elements to be rendered
      setTimeout(() => {
        attachButtonListeners();
      }, 100);
    });
    
    // Also try to attach listeners after a short delay in case DOMContentLoaded already fired
    setTimeout(() => {
      attachButtonListeners();
    }, 500);
  </script>
</body>
</html>
